using sv_eb3b1c04bb3141748105510167350206.Models;

namespace sv_eb3b1c04bb3141748105510167350206.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

using sv_eb3b1c04bb3141748105510167350206.Models;

namespace sv_eb3b1c04bb3141748105510167350206.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with egg, cheese, pancetta, and pepper.", 25),
            new(2, "Margherita Pizza", "Simple pizza with tomato sauce, mozzarella, and fresh basil.", 40),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 35),
        },
        [2] = new List<Recipe>
        {
            new(4, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts, vegetables, and chili peppers.", 30),
            new(5, "Mapo Tofu", "Silken tofu in a spicy, numbing sauce with minced pork.", 20),
            new(6, "Hot and Sour Soup", "Tangy broth with mushrooms, tofu, and bamboo shoots.", 25),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, onion, and cilantro.", 45),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, and jalapeño.", 10),
            new(9, "Chicken Enchiladas", "Corn tortillas filled with chicken and smothered in red sauce.", 50),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_eb3b1c04bb3141748105510167350206.Models
@using sv_eb3b1c04bb3141748105510167350206.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h3>Recipes for Cuisine @CuisineId</h3>

<div class="mb-3">
    <label class="form-label">Sort:</label>
    <select class="form-select w-auto d-inline-block" value="@Sort" @onchange="OnSortChanged">
        <option value="newest">Newest</option>
        <option value="popular">Popular</option>
    </select>
</div>

@if (_isRefreshing && _recipes is not null)
{
    <div class="alert alert-info py-1 px-2 d-inline-block" role="status">Refreshing…</div>
}

@if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <div class="placeholder-glow">
        <p class="placeholder col-6"></p>
        <p class="placeholder col-8"></p>
        <p class="placeholder col-5"></p>
    </div>
}
else
{
    <div class="list-group">
        @foreach (var recipe in GetSortedRecipes())
        {
            <div class="list-group-item">
                <h5>@recipe.Title</h5>
                <p class="mb-1">@recipe.Description</p>
                <small class="text-muted">Prep time: @recipe.PrepTimeMinutes min</small>
            </div>
        }
    </div>

    @if (!_recipes.Any())
    {
        <p class="text-muted">No recipes found for this cuisine.</p>
    }
}

@code {
    [Parameter] public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private bool _isRefreshing;
    private string? _errorMessage;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            // Only the sort parameter changed — no reload needed.
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var token = _cts.Token;
        var targetCuisineId = CuisineId;

        _errorMessage = null;
        _isRefreshing = _recipes is not null;

        if (_recipes is null)
        {
            StateHasChanged();
        }

        try
        {
            var results = await RecipeService.GetByCuisineAsync(targetCuisineId, token);

            if (token.IsCancellationRequested)
                return;

            _recipes = results;
            _loadedCuisineId = targetCuisineId;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Cancelled by us (new cuisine selected or navigated away) — do nothing.
        }
        catch (OperationCanceledException)
        {
            // Cancelled externally or timed out.
            Logger.LogWarning("Recipe loading for cuisine {CuisineId} timed out or was cancelled externally.", targetCuisineId);
            _isRefreshing = false;
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load recipes for cuisine {CuisineId}.", targetCuisineId);
            _isRefreshing = false;
            _errorMessage = "Something went wrong while loading recipes. Please try again.";
        }
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes.OrderBy(r => r.PrepTimeMinutes)
            : _recipes.OrderByDescending(r => r.Id);
    }

    private void OnSortChanged(ChangeEventArgs e)
    {
        var newSort = e.Value?.ToString() ?? "newest";
        Navigation.NavigateTo($"/recipes/{CuisineId}?sort={newSort}");
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

